INSERT INTO sql_expressions (id, "sql", source_name) VALUES
    (1250, '"Налоговые реквизиты ЮЛ.Признак резидента" = 1 and "Налоговые реквизиты ЮЛ.ИНН" IS NULL', 'УСЛиК'),
    (1161, 'syslib.utf8_length("ОСНОВНЫЕ СВЕДЕНИЯ.Место рождения") < 4', 'УСЛиК'),
    (1193, '"АДРЕС.Код страны" <> ''unknown'' and not regexp_like(cast("АДРЕС.Код страны" as string), ''^[0-9]{3}$'')', 'УСЛиК'),
    (1103, '"ДУЛ.Паспорт РФ.Тип ДУЛ" = ''21'' and "ДУЛ.Паспорт РФ.Дата выдачи" IS NULL', 'УСЛиК'),
    (1252, '"Налоговые реквизиты ЮЛ.Признак резидента" = 1 and "Налоговые реквизиты ЮЛ.ИНН" IS NOT NULL and "Налоговые реквизиты ЮЛ.Тип контрагента в ЕВД" = ''ИП'' and regexp_like ("Налоговые реквизиты ЮЛ.ИНН", ''^[0-9]+$'') and not (syslib.utf8_length("Налоговые реквизиты ЮЛ.ИНН") = 12 and substring("Налоговые реквизиты ЮЛ.ИНН", - 1, 1) = substring(cast((cast(substring("Налоговые реквизиты ЮЛ.ИНН", 1, 1) as int) * 3 + cast(substring("Налоговые реквизиты ЮЛ.ИНН", 2, 1) as int) * 7 + cast(substring("Налоговые реквизиты ЮЛ.ИНН", 3, 1) as int) * 2 + cast(substring("Налоговые реквизиты ЮЛ.ИНН", 4, 1) as int) * 4 + cast(substring("Налоговые реквизиты ЮЛ.ИНН", 5, 1) as int) * 10 + cast(substring("Налоговые реквизиты ЮЛ.ИНН", 6, 1) as int) * 3 + cast(substring("Налоговые реквизиты ЮЛ.ИНН", 7, 1) as int) * 5 + cast(substring("Налоговые реквизиты ЮЛ.ИНН", 8, 1) as int) * 9 + cast(substring("Налоговые реквизиты ЮЛ.ИНН", 9, 1) as int) * 4 + cast(substring("Налоговые реквизиты ЮЛ.ИНН", 10, 1) as int) * 6 + cast(substring("Налоговые реквизиты ЮЛ.ИНН", 11, 1) as int) * 8) % 11 as string), - 1, 1) and substring("Налоговые реквизиты ЮЛ.ИНН", - 2, 1) = substring(cast((cast(substring("Налоговые реквизиты ЮЛ.ИНН", 1, 1) as int) * 7 + cast(substring("Налоговые реквизиты ЮЛ.ИНН", 2, 1) as int) * 2 + cast(substring("Налоговые реквизиты ЮЛ.ИНН", 3, 1) as int) * 4 + cast(substring("Налоговые реквизиты ЮЛ.ИНН", 4, 1) as int) * 10 + cast(substring("Налоговые реквизиты ЮЛ.ИНН", 5, 1) as int) * 3 + cast(substring("Налоговые реквизиты ЮЛ.ИНН", 6, 1) as int) * 5 + cast(substring("Налоговые реквизиты ЮЛ.ИНН", 7, 1) as int) * 9 + cast(substring("Налоговые реквизиты ЮЛ.ИНН", 8, 1) as int) * 4 + cast(substring("Налоговые реквизиты ЮЛ.ИНН", 9, 1) as int) * 6 + cast(substring("Налоговые реквизиты ЮЛ.ИНН", 10, 1) as int) * 8) % 11 as string), - 1, 1))', 'УСЛиК'),
    (1255, '"Основные реквизиты ЮЛ.Признак резидента" = 1 and  "Основные реквизиты ЮЛ.Тип контрагента в ЕВД" != ''ИП'' and "Налоговые реквизиты ЮЛ.КПП1" IS NULL', 'УСЛиК'),
    (1253, '"Основные реквизиты ЮЛ.Признак резидента" = 0 and "Основные реквизиты ЮЛ.Тип контрагента в ЕВД" != ''ИП'' and "Налоговые реквизиты ЮЛ.ИНН" IS NULL and "Налоговые реквизиты ЮЛ.КИО" IS NULL', 'УСЛиК'),
    (10218, '"ДУЛ.Вид на жительство.Тип ДУЛ" = ''33'' and "ДУЛ.Вид на жительство.Номер"  is NULL', 'УСЛиК'),
    (1175, 'regexp_like("ОСНОВНЫЕ СВЕДЕНИЯ.ФИО одной строкой", ".*[^а-яА-ЯёЁa-zA-Z\\- .'']") AND "ОСНОВНЫЕ СВЕДЕНИЯ.ФИО одной строкой" IS NOT NULL', 'УСЛиК'),
    (1231, '"Данные о государственной регистрации ЮЛ.Признак резидента" = 1 and "Данные о государственной регистрации ЮЛ.ОГРН" IS NULL', 'УСЛиК'),
    (1228, '"Основные реквизиты ЮЛ.Признак резидента" = 1 and "Основные реквизиты ЮЛ.Полное фирменное наименование ЮЛ" IS NOT NULL and (length("Основные реквизиты ЮЛ.Полное фирменное наименование ЮЛ") < 5 or regexp_like ("Основные реквизиты ЮЛ.Полное фирменное наименование ЮЛ", ".*[a-zA-Z]"))', 'УСЛиК'),
    (1098, '"АДРЕС.Почтовый индекс" is not NULL and ("АДРЕС.Страна" in (''Российская Федерация'', ''Россия'', ''РФ'') OR CAST("АДРЕС.Код страны" AS string) = ''643'') and not regexp_like(trim("АДРЕС.Почтовый индекс"), ''^[0-9]{6}$'')', 'УСЛиК'),
    (1229, '"Основные реквизиты ЮЛ.Признак резидента" = 1 and "Основные реквизиты ЮЛ.Сокращенное фирменное наименование ЮЛ" IS NULL', 'УСЛиК'),
    (10189, 'regexp_like ("АДРЕС. Улица", ".*[- ]$")', 'УСЛиК'),
    (1192, '1 = 1 and ("АДРЕС.Код страны"= ''unknown'' or "АДРЕС.Код страны" IS NULL)', 'УСЛиК'),
    (1083, 'regexp_like("ОСНОВНЫЕ СВЕДЕНИЯ.Фамилия", ".*[^а-яА-ЯёЁa-zA-Z\\- .'']") AND "ОСНОВНЫЕ СВЕДЕНИЯ.Фамилия" IS NOT NULL', 'УСЛиК'),
    (1164, '"АДРЕС.Страна" IS NULL', 'УСЛиК'),
    (10106, '"ДУЛ.Военный билет.Тип ДУЛ" = ''25'' and "ДУЛ.Военный билет.Номер" is null', 'УСЛиК'),
    (1124, '"ДУЛ.Вид на жительство.Тип ДУЛ" = ''33'' and "ДУЛ.Вид на жительство.Дата начала срока действия" IS NULL', 'УСЛиК'),
    (1097, 'syslib.utf8_length("АДРЕС.Наименование города") > 30', 'УСЛиК'),
    (1084, '"ОСНОВНЫЕ СВЕДЕНИЯ.Фамилия" is not null and regexp_like("ОСНОВНЫЕ СВЕДЕНИЯ.Фамилия", ''^[\\-\\ ]|.*[\\-\\ ]$'') and syslib.utf8_length("ОСНОВНЫЕ СВЕДЕНИЯ.Фамилия") > 1', 'УСЛиК'),
    (1070, 'regexp_like("ОСНОВНЫЕ СВЕДЕНИЯ.Имя", ''^[\\-\\ ]|.*[\\-\\ ]$'') and syslib.utf8_length("ОСНОВНЫЕ СВЕДЕНИЯ.Имя") > 1', 'УСЛиК'),
    (1247, '"Государственные и финансовые коды.Признак резидента" = 1 and "Государственные и финансовые коды.Код страны регистрации" = ''RUS'' and "Государственные и финансовые коды.ОКОПФ" IS NOT NULL and (not regexp_like ("Государственные и финансовые коды.ОКАТО", ''^[0-9]+$'') or length("Государственные и финансовые коды.ОКАТО") <> 11)', 'УСЛиК'),
    (1121, '"ДУЛ.Свидетельство о рождении.Тип ДУЛ" = ''27'' and "ДУЛ.Свидетельство о рождении.Дата выдачи" < "ДУЛ.Свидетельство о рождении.Дата рождения"', 'УСЛиК'),
    (1118, '"ДУЛ.Свидетельство о рождении.Тип ДУЛ" = ''27'' and "ДУЛ.Свидетельство о рождении.Дата выдачи" > now()', 'УСЛиК'),
    (1095, 'regexp_like("АДРЕС.Наименование города", ".*^[\\-\\ ].*")', 'УСЛиК'),
    (1147, '"ДУЛ.Миграционная карта.Тип ДУЛ" = ''39'' and not regexp_like ("ДУЛ.Миграционная карта.Номер", ".*[a-zA-Zа-яА-ЯёЁ0-9]+.")', 'УСЛиК'),
    (1072, '"ОСНОВНЫЕ СВЕДЕНИЯ.Место рождения" IS NULL', 'УСЛиК'),
    (1107, '"ДУЛ.Паспорт РФ.Тип ДУЛ" = ''21'' and (not regexp_like ("ДУЛ.Паспорт РФ.Номер", ''^[0-9]{6}$'') OR CAST("ДУЛ.Паспорт РФ.Номер"AS INT) NOT BETWEEN 101 AND 999999)', 'УСЛиК'),
    (1106, '"ДУЛ.Паспорт РФ.Тип ДУЛ" = ''21'' and syslib.utf8_substr("ДУЛ.Паспорт РФ.Код подразделения", 1, length("ДУЛ.Паспорт РФ.Код подразделения")) is null', 'УСЛиК'),
    (1117, '"ДУЛ.Свидетельство о рождении.Тип ДУЛ" = ''27'' and "ДУЛ.Свидетельство о рождении.Дата выдачи" IS NULL', 'УСЛиК'),
    (1075, 'regexp_like ("ОСНОВНЫЕ СВЕДЕНИЯ.Место рождения", ".*[- ]$")', 'УСЛиК'),
    (1179, '"ДУЛ.Паспорт РФ.Тип ДУЛ" = ''21'' and not REGEXP_LIKE ("ДУЛ.Паспорт РФ.Кем выдан", ".*[а-яА-ЯёЁa-zA-Z]")', 'УСЛиК'),
    (1234, '"Государственные и финансовые коды.Признак резидента" = 1 and "Государственные и финансовые коды.ОКПО/Идентификационный номер ТОСП" IS NULL', 'УСЛиК'),
    (1116, '"ДУЛ.Свидетельство о рождении.Тип ДУЛ" = ''27'' and not regexp_like ("ДУЛ.Свидетельство о рождении.Номер", ''^[0-9]{6}$'')', 'УСЛиК'),
    (1066, '"ОСНОВНЫЕ СВЕДЕНИЯ.Имя" IS NULL', 'УСЛиК'),
    (1068, 'regexp_like("ОСНОВНЫЕ СВЕДЕНИЯ.Имя", ".*[^а-яА-ЯёЁa-zA-Z\\- .'']") AND "ОСНОВНЫЕ СВЕДЕНИЯ.Имя" IS NOT NULL', 'УСЛиК'),
    (1096, 'regexp_like ("АДРЕС.Наименование города", ".*[- ]$")', 'УСЛиК'),
    (1076, 'regexp_like("ОСНОВНЫЕ СВЕДЕНИЯ.Отчество", ".*[a-zA-Z]+.*") and regexp_like("ОСНОВНЫЕ СВЕДЕНИЯ.Отчество", ".*[а-яА-ЯеЁ]+.*")', 'УСЛиК'),
    (1146, '"КОНТАКТ.Телефон.Номер телефона" IS NULL', 'УСЛиК'),
    (1112, '"ДУЛ.Паспорт РФ.Тип ДУЛ" = ''21'' AND NOT regexp_like("ДУЛ.Паспорт РФ.Серия", ''^[0-9]{4}$'') AND NOT regexp_like("ДУЛ.Паспорт РФ.Серия", ''^[0-9]{2}[\\ -]?[0-9]{2}$'')', 'УСЛиК'),
    (1073, 'regexp_like("ОСНОВНЫЕ СВЕДЕНИЯ.Место рождения", ".*[a-zA-Z]+.*") and regexp_like("ОСНОВНЫЕ СВЕДЕНИЯ.Место рождения", ".*[а-яА-ЯеЁ]+.*")', 'УСЛиК'),
    (1087, '"ОСНОВНЫЕ СВЕДЕНИЯ.ФИО одной строкой" is null', 'УСЛиК'),
    (1171, '"ОСНОВНЫЕ СВЕДЕНИЯ.Дата рождения" in to_dates(''1900-01-01'', ''1900-01-02'', ''1900-02-01'', ''1900-02-02'', ''1901-01-01'', ''1910-01-01'', ''1911-11-11'', ''1917-10-25'')', 'УСЛиК'),
    (1115, '"ДУЛ.Свидетельство о рождении.Тип ДУЛ" = ''27'' and "ДУЛ.Свидетельство о рождении.Номер" IS NULL', 'УСЛиК'),
    (1197, '("ДУЛ (все типы).Тип ДУЛ" in (''21'', ''22'', ''26'', ''27'', ''28'') and "ДУЛ (все типы).ИД Страны" not in (0, 51625)) or ("ДУЛ (все типы).Тип ДУЛ" in (''31'', ''32'', ''33'', ''34'', ''35'', ''36'', ''37'', ''39'', ''30'', ''99'') and "ДУЛ (все типы).ИД Страны" = 51625)', 'УСЛиК'),
    (1120, '"ДУЛ.Свидетельство о рождении.Тип ДУЛ" = ''27'' and syslib.utf8_length("ДУЛ.Свидетельство о рождении.Кем выдан") < 5', 'УСЛиК'),
    (1166, 'regexp_like("АДРЕС.Населенный пункт", ".*[a-zA-Z]+.*") and regexp_like ("АДРЕС.Населенный пункт", ".*[а-яА-ЯёЁ]+.*")', 'УСЛиК'),
    (10188, 'regexp_like("АДРЕС. Улица", ".*^[\\-\\ ].*")', 'УСЛиК'),
    (10200, '"АДРЕС.Улица" IS NULL', 'УСЛиК'),
    (1162, 'regexp_like("ОСНОВНЫЕ СВЕДЕНИЯ.Отчество", ".*[^а-яА-ЯёЁa-zA-Z\\- .'']") AND "ОСНОВНЫЕ СВЕДЕНИЯ.Отчество" IS NOT NULL', 'УСЛиК'),
    (1258, '"Государственные и финансовые коды.Тип контрагента в ЕВД" = ''БАНК'' and "Государственные и финансовые коды.БИК" IS NULL', 'УСЛиК'),
    (1099, '"АДРЕС.Почтовый индекс" is not NULL and "АДРЕС.Почтовый индекс" in (''111111'', ''222222'', ''333333'', ''444444'', ''555555'', ''666666'', ''777777'', ''888888'', ''999999'', ''000000'', ''123456'', ''234567'', ''345678'', ''567890'')', 'УСЛиК'),
    (10248, '"ДУЛ.Разрешение на временное проживание.Тип ДУЛ" = ''34'' and "ДУЛ.Разрешение на временное проживание.Дата выдачи"< "ДУЛ.Разрешение на временное проживание.Дата рождения"', 'УСЛиК'),
    (1119, '"ДУЛ.Свидетельство о рождении.Тип ДУЛ" = ''27'' and "ДУЛ.Свидетельство о рождении.Кем выдан" IS NULL', 'УСЛиК'),
    (1079, '"ОСНОВНЫЕ СВЕДЕНИЯ.Пол" IS NULL or "ОСНОВНЫЕ СВЕДЕНИЯ.Пол" not in (''M'', ''F'')', 'УСЛиК'),
    (1259, '"Основные реквизиты ЮЛ.Признак резидента" = 1  and syslib.utf8_length("Государственные и финансовые коды.БИК") <> 9', 'УСЛиК'),
    (10078, '"ДУЛ.Военный билет.Тип ДУЛ" = ''25'' and "ДУЛ.Военный билет.Дата выдачи" > now()', 'УСЛиК'),
    (1074, 'regexp_like ("ОСНОВНЫЕ СВЕДЕНИЯ.Место рождения", ''^[0-9-,.\\(\\)\\/ ]'')', 'УСЛиК'),
    (1078, 'regexp_like("ОСНОВНЫЕ СВЕДЕНИЯ.Отчество", ''^[\\-\\ ]|.*[\\-\\ ]$'') and syslib.utf8_length("ОСНОВНЫЕ СВЕДЕНИЯ.Отчество") > 1', 'УСЛиК'),
    (1113, '"ДУЛ.Свидетельство о рождении.Тип ДУЛ" = ''27'' and "ДУЛ.Свидетельство о рождении.Серия" IS NULL', 'УСЛиК'),
    (1081, '"ОСНОВНЫЕ СВЕДЕНИЯ.Фамилия" is not NULL and "ОСНОВНЫЕ СВЕДЕНИЯ.Фамилия" regexp ".*[a-zA-Z]+.*" AND "ОСНОВНЫЕ СВЕДЕНИЯ.Фамилия" regexp ".*[а-яА-ЯеЁ]+.*"', 'УСЛиК'),
    (1137, '"ДУЛ.Миграционная карта.Тип ДУЛ" = ''39'' and "ДУЛ.Миграционная карта.Дата окончания срока действия" IS NULL', 'УСЛиК'),
    (10196, 'regexp_like("АДРЕС.Населенный пункт", ".*[a-zA-Z]+.*") AND (UPPER("АДРЕС.Страна") IN (''RUS'', ''РОССИЙСКАЯ ФЕДЕРАЦИЯ'', ''РОССИЯ'', ''РФ'') AND "АДРЕС.Страна" LIKE ''%643%'')', 'УСЛиК'),
    (1125, '"ДУЛ.Вид на жительство.Тип ДУЛ" = ''33'' and "ДУЛ.Вид на жительство.Дата начала срока действия" IS NOT NULL and ("ДУЛ.Вид на жительство.Дата начала срока действия" > now() or "ДУЛ.Вид на жительство.Дата начала срока действия" > "ДУЛ.Вид на жительство.Дата окончания срока действия")', 'УСЛиК'),
    (1069, 'regexp_like("ОСНОВНЫЕ СВЕДЕНИЯ.Имя", ".*[a-zA-Z]+.*") and regexp_like("ОСНОВНЫЕ СВЕДЕНИЯ.Имя", ".*[а-яА-ЯеЁ]+.*")', 'УСЛиК'),
    (1143, '"АДРЕС.Наименование региона" is not NULL AND (UPPER("АДРЕС.Страна") IN (''RUS'', ''РОССИЙСКАЯ ФЕДЕРАЦИЯ'', ''РОССИЯ'', ''РФ'') or "АДРЕС.Страна" LIKE ''%643%'') and regexp_like("АДРЕС.Наименование региона", ".*[^А-Яа-яЁё ()-].*") and "АДРЕС.Наименование региона" != ''N/A''', 'УСЛиК'),
    (1248, '"Государственные и финансовые коды.Признак резидента" = 1 and "Государственные и финансовые коды.ОКВЭД2" IS NULL', 'УСЛиК'),
    (10192, '1=1 AND regexp_like("ОСНОВНЫЕ СВЕДЕНИЯ.Имя", ''([А-Яа-яёЁA-Za-z])\\1{2,}'')  OR regexp_like("ОСНОВНЫЕ СВЕДЕНИЯ.Имя", ''[^A-Za-zА-Яа-яёЁ0-9 ]'') AND LENGTH(REGEXP_REPLACE("ОСНОВНЫЕ СВЕДЕНИЯ.Имя", ''[^A-Za-zА-Яа-яёЁ0-9]'', '''')) < LENGTH("ОСНОВНЫЕ СВЕДЕНИЯ.Имя") - 1', 'УСЛиК'),
    (1249, '"Государственные и финансовые коды.Признак резидента" = 1 and "Государственные и финансовые коды.ОКВЭД2" IS NOT NULL and (length("Государственные и финансовые коды.ОКВЭД2") < 4 or length("Государственные и финансовые коды.ОКВЭД2") > 8 or not regexp_like ("Государственные и финансовые коды.ОКВЭД2", ''^[0-9][0-9\\.]*$''))', 'УСЛиК'),
    (1194, '(UPPER("АДРЕС.Страна") IN (''RUS'', ''РОССИЙСКАЯ ФЕДЕРАЦИЯ'', ''РОССИЯ'', ''РФ'') OR "АДРЕС.Страна" LIKE ''%643%'') AND "АДРЕС.Район" IS NOT NULL AND regexp_like("АДРЕС.Район", "^[^А-Яа-яЁё]|.*[^А-Яа-яЁё0-9 \\-№.].*")', 'УСЛиК'),
    (10081, '"ДУЛ.Дипломатический паспорт гражданина РФ.Тип ДУЛ" = ''22'' and "ДУЛ.Дипломатический паспорт гражданина РФ.Наименование типа ДУЛ" LIKE ''%Дипломатический%''  and "ДУЛ.Дипломатический паспорт гражданина РФ.Дата выдачи" > now()', 'УСЛиК'),
    (1086, '"ИНН.Номер свидетельства" IS NOT NULL and not regexp_like ("ИНН.Номер свидетельства", ''^[0-9]{12}$'') and "ИНН.Страна"= ''RUS''', 'УСЛиК'),
    (1148, '"ОСНОВНЫЕ СВЕДЕНИЯ.Дата рождения" IS NULL', 'УСЛиК'),
    (1090, 'regexp_like("ОСНОВНЫЕ СВЕДЕНИЯ.ФИО одной строкой", ''^[\\-\\ ]|.*[\\-\\ ]$'') and syslib.utf8_length("ОСНОВНЫЕ СВЕДЕНИЯ.ФИО одной строкой") > 1', 'УСЛиК'),
    (1092, '"ИНН.Номер свидетельства" IS NOT NULL and SUBSTRING("ИНН.Номер свидетельства", 1, 2) in (''00'')', 'УСЛиК'),
    (1080, '"ОСНОВНЫЕ СВЕДЕНИЯ.СНИЛС" IS NOT NULL and syslib.utf8_length(replace(replace("ОСНОВНЫЕ СВЕДЕНИЯ.СНИЛС", ''-'', ''''), '' '', '''')) <> 11', 'УСЛиК'),
    (10080, '"ДУЛ.Дипломатический паспорт гражданина РФ.Тип ДУЛ" = ''22'' and "ДУЛ.Дипломатический паспорт гражданина РФ.Наименование типа ДУЛ" LIKE ''%Дипломатический%''  and "ДУЛ.Дипломатический паспорт гражданина РФ.Дата выдачи" is null', 'УСЛиК'),
    (1108, '"ДУЛ.Паспорт РФ.Тип ДУЛ" = ''21'' AND "ДУЛ.Паспорт РФ.Кем выдан" IS NULL', 'УСЛиК'),
    (1109, '"ДУЛ.Паспорт РФ.Тип ДУЛ" = ''21'' AND "ДУЛ.Паспорт РФ.Серия" IS NULL', 'УСЛиК'),
    (10079, '"ДУЛ.Военный билет.Тип ДУЛ" = ''25'' and "ДУЛ.Военный билет.Дата выдачи" < "ДУЛ.Военный билет.Дата рождения"', 'УСЛиК'),
    (1105, '"ДУЛ.Паспорт РФ.Тип ДУЛ" = ''21'' and regexp_like ("ДУЛ.Паспорт РФ.Код подразделения", ''^[0-9]{2}[6-9]-[0-9]{3}$'')', 'УСЛиК'),
    (1088, '"ОСНОВНЫЕ СВЕДЕНИЯ.ФИО одной строкой" regexp ".*[a-zA-Z]+.*" AND "ОСНОВНЫЕ СВЕДЕНИЯ.ФИО одной строкой" regexp ".*[а-яА-ЯеЁ]+.*"', 'УСЛиК'),
    (10083, '"ДУЛ.Загранпаспорт гражданина РФ.Тип ДУЛ" = ''22'' and "ДУЛ.Загранпаспорт гражданина РФ.Наименование типа ДУЛ" LIKE ''%Заграничный%'' and "ДУЛ.Загранпаспорт гражданина РФ.Дата выдачи" is null', 'УСЛиК'),
    (1130, '"ДУЛ.Паспорт РФ.Тип ДУЛ" = ''21'' and ("ДУЛ.Паспорт РФ.Дата выдачи" < to_date(''1997-10-01'') or "ДУЛ.Паспорт РФ.Дата выдачи" > now()) and "ДУЛ.Паспорт РФ.Дата выдачи" > years_add("ДУЛ.Паспорт РФ.Дата рождения" , 14)', 'УСЛиК'),
    (10072, '"ДУЛ.Миграционная карта.Тип ДУЛ" = ''39'' and "ДУЛ.Миграционная карта.Дата выдачи" > now()', 'УСЛиК'),
    (10077, '"ДУЛ.Военный билет.Тип ДУЛ" = ''25'' and "ДУЛ.Военный билет.Дата выдачи" is null', 'УСЛиК'),
    (10076, '"ДУЛ.Временное удостоверение личности гражданина РФ.Тип ДУЛ" = ''26'' and "ДУЛ.Временное удостоверение личности гражданина РФ.Дата выдачи" < "ДУЛ.Временное удостоверение личности гражданина РФ.Дата рождения"', 'УСЛиК'),
    (1227, '"Основные реквизиты ЮЛ.Признак резидента" = 1 and "Основные реквизиты ЮЛ.Полное фирменное наименование ЮЛ" is NULL', 'УСЛиК'),
    (10088, '"ДУЛ.Удостоверение личности военнослужащего.Тип ДУЛ" = ''24'' and "ДУЛ.Удостоверение личности военнослужащего.Дата выдачи" <  "ДУЛ.Удостоверение личности военнослужащего.Дата рождения"', 'УСЛиК'),
    (10121, '"ОСНОВНЫЕ СВЕДЕНИЯ.Фамилия" IS NULL and "ОСНОВНЫЕ СВЕДЕНИЯ.Код страны рождения" NOT IN (''AFG'', ''ERI'', ''IND'', ''ISL'', ''MMR'', ''IDN'')', 'УСЛиК'),
    (1094, '(UPPER("АДРЕС.Страна") IN (''RUS'', ''РОССИЙСКАЯ ФЕДЕРАЦИЯ'', ''РОССИЯ'', ''РФ'') or "АДРЕС.Страна" LIKE ''%643%'') AND regexp_like("АДРЕС.Наименование города", ''^[^А-Яа-яЁё]|.*[^А-Яа-яЁё0-9 \\-.].*'')', 'УСЛиК'),
    (1126, '"ДУЛ.Вид на жительство.Тип ДУЛ" = ''33'' and "ДУЛ.Вид на жительство.Дата начала срока действия" < CAST(''2019-11-01'' as date) and "ДУЛ.Вид на жительство.Дата окончания срока действия" is null', 'УСЛиК'),
    (1110, '"ДУЛ.Паспорт РФ.Тип ДУЛ" = ''21'' AND regexp_like("ДУЛ.Паспорт РФ.Кем выдан", ''^б/с$|^б/н$|^н/д$'')', 'УСЛиК'),
    (10075, '"ДУЛ.Временное удостоверение личности гражданина РФ.Тип ДУЛ" = ''26'' and "ДУЛ.Временное удостоверение личности гражданина РФ.Дата выдачи" > now()', 'УСЛиК'),
    (10201, '"ДУЛ.Паспорт РФ.Тип ДУЛ" = ''21'' and regexp_like ("ДУЛ.Паспорт РФ.Кем выдан", ".*[a-zA-Z]")', 'УСЛиК'),
    (1338, '(UPPER("АДРЕС.Страна") IN (''RUS'', ''РОССИЙСКАЯ ФЕДЕРАЦИЯ'', ''РОССИЯ'', ''РФ'') or "АДРЕС.Страна" LIKE ''%643%'') AND ("АДРЕС.Наименование региона" is null or "АДРЕС.Наименование региона" = ''N/A'')', 'УСЛиК'),
    (1257, '"Данные о государственной регистрации ЮЛ.Код страны регистрации" = ''unknown'' AND "Данные о государственной регистрации ЮЛ.Идентификатор системы-источника"  != 258', 'УСЛиК')
